// ==========================================
// STRATEGIC DATA AGGREGATOR
// Builds the full picture for strategy
// ==========================================
const revenue = $('Read Revenue').all();
const content = $('Read Content').all();
const patterns = $('Read Patterns').all();
const competitors = $('Read Competitors').all();
const learning = $('Read Learning History').all();
const brainLogs = $('Read Brain Decisions').all();

// === REVENUE ANALYSIS ===
const totalCustomers = revenue.length;
const totalRevenue = revenue.reduce((s, r) => s + (r.json.amount || r.json.Amount || 350), 0);
const avgTicket = totalCustomers > 0 ? Math.round(totalRevenue / totalCustomers) : 0;
const paidCustomers = revenue.filter(r => (r.json.status || r.json.Status) === 'paid').length;
const pendingCustomers = revenue.filter(r => (r.json.status || r.json.Status) === 'pending').length;

// Revenue by source
const sources = {};
revenue.forEach(r => {
  const src = r.json.source || r.json.Source || 'unknown';
  sources[src] = (sources[src] || 0) + 1;
});
const topSource = Object.entries(sources).sort((a, b) => b[1] - a[1])[0];

// Revenue by platform
const platforms = {};
revenue.forEach(r => {
  const p = r.json.platform || r.json.Platform || 'unknown';
  platforms[p] = (platforms[p] || 0) + 1;
});
const topPlatform = Object.entries(platforms).sort((a, b) => b[1] - a[1])[0];

// === CONTENT ANALYSIS ===
const totalVideos = content.length;
const avgScore = content.length > 0
  ? Math.round(content.reduce((s, c) => s + (c.json.performance_score || c.json['Performance Score'] || 0), 0) / content.length)
  : 0;
const totalDMs = content.reduce((s, c) => s + (c.json.dms_generated || c.json['DMs Generated'] || 0), 0);
const totalViews = content.reduce((s, c) => s + (c.json.views || c.json.Views || 0), 0);
const scaledVideos = content.filter(c => (c.json.status || c.json.Status) === 'scaling').length;
const killedVideos = content.filter(c => (c.json.status || c.json.Status) === 'killed').length;

// Best angle
const angleScores = {};
content.forEach(c => {
  const angle = c.json.angle || c.json.Angle || 'unknown';
  const score = c.json.performance_score || c.json['Performance Score'] || 0;
  if (!angleScores[angle]) angleScores[angle] = { total: 0, count: 0, dms: 0 };
  angleScores[angle].total += score;
  angleScores[angle].count++;
  angleScores[angle].dms += (c.json.dms_generated || c.json['DMs Generated'] || 0);
});
let bestAngle = { name: 'none', avgScore: 0, totalDMs: 0 };
Object.entries(angleScores).forEach(([name, data]) => {
  const avg = data.total / data.count;
  if (avg > bestAngle.avgScore) bestAngle = { name, avgScore: Math.round(avg), totalDMs: data.dms };
});

// === CONVERSION FUNNEL ===
const conversionRate = totalDMs > 0 ? (paidCustomers / totalDMs * 100) : 0;
const viewToDM = totalViews > 0 ? (totalDMs / totalViews * 100) : 0;
const dmToSale = totalDMs > 0 ? (paidCustomers / totalDMs * 100) : 0;

// === PATTERNS ===
const scalePatterns = patterns.filter(p => (p.json.result || p.json.Result) === 'SCALE');
const killPatterns = patterns.filter(p => (p.json.result || p.json.Result) === 'KILL');
const winRate = patterns.length > 0 ? Math.round(scalePatterns.length / patterns.length * 100) : 0;

// === COMPETITORS ===
const competitorData = competitors.map(c => ({
  name: c.json.name || c.json.Name || '',
  price: c.json.price || c.json.Price || 0,
  followers: c.json.followers || c.json.Followers || 0,
  threat: c.json.threat_level || c.json['Threat Level'] || 'low',
  offer: c.json.offer_type || c.json['Offer Type'] || '',
  lastMove: c.json.last_move || c.json['Last Move'] || ''
}));
const avgCompPrice = competitorData.length > 0
  ? Math.round(competitorData.reduce((s, c) => s + c.price, 0) / competitorData.length)
  : 0;
const highThreats = competitorData.filter(c => c.threat === 'high');

// === LEARNING HISTORY ===
const latestLearning = learning.length > 0 ? learning[learning.length - 1].json : {};
const overallAccuracy = learning.length > 0
  ? Math.round(learning.reduce((s, l) => s + (l.json.accuracy || l.json.Accuracy || 0), 0) / learning.length)
  : 0;

// === BRAIN HISTORY ===
const totalDecisions = brainLogs.length;
const successDecisions = brainLogs.filter(b => (b.json.outcome || b.json.Outcome) === 'success').length;
const brainAccuracy = totalDecisions > 0 ? Math.round(successDecisions / totalDecisions * 100) : 0;

// === TIME ===
const deadline = new Date('2026-04-05T23:59:59');
const now = new Date();
const daysLeft = Math.max(0, Math.round((deadline - now) / (1000 * 60 * 60 * 24)));
const target = 1500;
const remaining = target - totalCustomers;
const dailyNeeded = daysLeft > 0 ? Math.round(remaining / daysLeft) : remaining;

return {
  json: {
    revenue: {
      total_customers: totalCustomers,
      paid: paidCustomers,
      pending: pendingCustomers,
      total_revenue: totalRevenue,
      avg_ticket: avgTicket,
      top_source: topSource ? { name: topSource[0], count: topSource[1] } : null,
      top_platform: topPlatform ? { name: topPlatform[0], count: topPlatform[1] } : null,
      sources
    },
    content: {
      total_videos: totalVideos,
      avg_score: avgScore,
      total_dms: totalDMs,
      total_views: totalViews,
      scaled: scaledVideos,
      killed: killedVideos,
      best_angle: bestAngle
    },
    funnel: {
      view_to_dm_pct: viewToDM.toFixed(2),
      dm_to_sale_pct: dmToSale.toFixed(1),
      overall_conversion_pct: conversionRate.toFixed(1)
    },
    patterns: {
      total: patterns.length,
      scale: scalePatterns.length,
      kill: killPatterns.length,
      win_rate: winRate
    },
    competitors: {
      total: competitorData.length,
      avg_price: avgCompPrice,
      high_threats: highThreats.length,
      data: competitorData
    },
    learning: {
      overall_accuracy: overallAccuracy,
      latest_rules: latestLearning['Rules Added'] || latestLearning.rules_added || '',
      latest_focus: latestLearning['Tomorrow Focus'] || latestLearning.tomorrow_focus || ''
    },
    brain: {
      total_decisions: totalDecisions,
      success_rate: brainAccuracy
    },
    time: {
      days_left: daysLeft,
      target,
      remaining,
      daily_needed: dailyNeeded
    },
    timestamp: now.toISOString()
  }
};

