const response = $input.item.json;
const data = $('Strategic Data Aggregator').item.json;
let strategy;

try {
  const content = response.content?.[0]?.text || '{}';
  let jsonStr = content;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  strategy = JSON.parse(jsonStr);
} catch (e) {
  strategy = {
    strategy: { direction: 'خطأ في التحليل', primary_bet: '', secondary_bet: '', kill_zone: '', timeframe: '' },
    positioning: { vs_competitors: '', unique_value: '', messaging_core: '', emotion_to_lead_with: '' },
    growth_levers: [],
    pricing_strategy: { current: 350, recommendation: 'keep', new_price_or_tiers: '350', reason: 'خطأ' },
    resource_allocation: { content_production_pct: 40, sales_closing_pct: 30, competitor_intel_pct: 10, experimentation_pct: 20, reason: 'default' },
    offer_recommendation: { primary_offer: '', upsell: '', scarcity_angle: '', new_offer_idea: '' },
    risks: [],
    one_line_mandate: 'مراجعة يدوية مطلوبة'
  };
}

strategy.meta = {
  timestamp: new Date().toISOString(),
  snapshot: {
    customers: data.revenue.total_customers,
    revenue: data.revenue.total_revenue,
    days_left: data.time.days_left,
    avg_score: data.content.avg_score,
    best_angle: data.content.best_angle.name,
    conversion: data.funnel.overall_conversion_pct
  }
};

return { json: strategy };

